using System;
using System.Linq;
using System.Reflection;
using SkiaSharp;

Console.WriteLine($"SkiaSharp Version: {typeof(SKCanvas).Assembly.GetName().Version}");

var drawSurfaceMethods = typeof(SKCanvas).GetMethods(BindingFlags.Public | BindingFlags.Instance)
    .Where(m => m.Name == "DrawSurface").ToList();
foreach (var m in drawSurfaceMethods)
{
    var pars = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
    Console.WriteLine($"  DrawSurface({pars})");
}
Console.WriteLine($"Has SKSamplingOptions: {drawSurfaceMethods.Any(m => m.GetParameters().Any(p => p.ParameterType.Name.Contains("SKSamplingOptions")))}");

var surfaceDrawMethods = typeof(SKSurface).GetMethods(BindingFlags.Public | BindingFlags.Instance)
    .Where(m => m.Name == "Draw").ToList();
Console.WriteLine($"SKSurface.Draw has SKSamplingOptions: {surfaceDrawMethods.Any(m => m.GetParameters().Any(p => p.ParameterType.Name.Contains("SKSamplingOptions")))}");

var imageHasSampling = typeof(SKCanvas).GetMethods(BindingFlags.Public | BindingFlags.Instance)
    .Where(m => m.Name == "DrawImage")
    .Any(m => m.GetParameters().Any(p => p.ParameterType.Name.Contains("SKSamplingOptions")));
Console.WriteLine($"DrawImage has SKSamplingOptions: {imageHasSampling}");

using var src = SKSurface.Create(new SKImageInfo(100, 100));
using var snapshot = src.Snapshot();
var sampling = new SKSamplingOptions(SKFilterMode.Linear, SKMipmapMode.Linear);
using var dst = SKSurface.Create(new SKImageInfo(200, 200));
dst.Canvas.DrawImage(snapshot, 50, 50, sampling);
Console.WriteLine("Workaround (Snapshot + DrawImage): OK");
Console.WriteLine("SUCCESS: test completed");

actions.comment:
Thanks for reporting this! We investigated and can confirm that `SKCanvas.DrawSurface` and `SKSurface.Draw` do not accept `SKSamplingOptions` — the overloads are missing across all current versions (3.116.0, 3.119.2, and main).

**Investigation:**
- `SKCanvas.DrawSurface` has 2 overloads (point and x/y variants), none accepting `SKSamplingOptions`
- `SKSurface.Draw` has 1 overload, no `SKSamplingOptions`
- In contrast, `SKCanvas.DrawImage` has 8 overloads, 4 of which accept `SKSamplingOptions`
- The upstream Skia C++ `SkSurface::draw` does support a sampling parameter, but the C API shim only wraps the convenience overload

**Workaround:** You can use `SKSurface.Snapshot()` + `SKCanvas.DrawImage` which already supports sampling:

```csharp
// Instead of: canvas.DrawSurface(surface, x, y, paint);
using var image = surface.Snapshot();
var sampling = new SKSamplingOptions(SKFilterMode.Linear, SKMipmapMode.Linear);
canvas.DrawImage(image, x, y, sampling, paint);
```

PR #3491 is open to add the missing overloads. We've flagged this for inclusion.

